  methodName: string;
  methodVersion: string;
  domain: string;
  sampleSize: number;
  weightedBrier: unknown;
  calibrationSlope: unknown;
  calibrationSlopeCiLow: unknown;
  calibrationSlopeCiHigh: unknown;
